def validate(args, output):
    nums = args[0]
    avail = list(nums)
    if not isinstance(output, list):
        return False
    # every element must come from nums (distinct values, used at most once)
    pool = {}
    for v in nums:
        pool[v] = pool.get(v, 0) + 1
    for v in output:
        if pool.get(v, 0) <= 0:
            return False
        pool[v] -= 1
    # pairwise divisibility
    s = sorted(output)
    for i in range(1, len(s)):
        if s[i] % s[i - 1] != 0:
            return False
    # completeness: size must equal the true maximum
    arr = sorted(set(nums))
    n = len(arr)
    if n == 0:
        return len(output) == 0
    dp = [1] * n
    for i in range(n):
        for j in range(i):
            if arr[i] % arr[j] == 0 and dp[j] + 1 > dp[i]:
                dp[i] = dp[j] + 1
    best = max(dp)
    return len(output) == best

