function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output)) return false;
    const pool = new Map();
    for (const v of nums) pool.set(v, (pool.get(v) || 0) + 1);
    for (const v of output) {
        const c = pool.get(v) || 0;
        if (c <= 0) return false;
        pool.set(v, c - 1);
    }
    const s = output.slice().sort((a, b) => a - b);
    for (let i = 1; i < s.length; i++) {
        if (s[i] % s[i - 1] !== 0) return false;
    }
    const arr = Array.from(new Set(nums)).sort((a, b) => a - b);
    const n = arr.length;
    if (n === 0) return output.length === 0;
    const dp = new Array(n).fill(1);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            if (arr[i] % arr[j] === 0 && dp[j] + 1 > dp[i]) dp[i] = dp[j] + 1;
        }
    }
    let best = 0;
    for (const d of dp) if (d > best) best = d;
    return output.length === best;
}

