class Solution:
    def largestDivisibleSubset(self, nums):
        arr = sorted(nums)
        n = len(arr)
        if n == 0:
            return []
        best_chain = []
        def dfs(idx, chain):
            nonlocal best_chain
            if len(chain) > len(best_chain):
                best_chain = chain[:]
            for j in range(idx, n):
                if not chain or arr[j] % chain[-1] == 0:
                    chain.append(arr[j])
                    dfs(j + 1, chain)
                    chain.pop()
        # bounded brute search is only safe for small inputs; use DP reconstruction instead
        dp = [1] * n
        parent = [-1] * n
        for i in range(n):
            for j in range(i):
                if arr[i] % arr[j] == 0 and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
                    parent[i] = j
        end = max(range(n), key=lambda i: dp[i])
        res = []
        while end != -1:
            res.append(arr[end])
            end = parent[end]
        res.reverse()
        return res

