class Solution:
    def largestDivisibleSubset(self, nums):
        arr = sorted(nums)
        n = len(arr)
        if n == 0:
            return []
        dp = [1] * n
        parent = [-1] * n
        best = 0
        for i in range(n):
            for j in range(i):
                if arr[i] % arr[j] == 0 and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
                    parent[i] = j
            if dp[i] > dp[best]:
                best = i
        res = []
        k = best
        while k != -1:
            res.append(arr[k])
            k = parent[k]
        res.reverse()
        return res

